private class IapCache(private val store: SecureStore) {
    private val keyProducts = "iap_products_snapshot_v1"
    private val keyOwned = "iap_owned_purchases_v1"

    fun saveProductSnapshot(products: List<IapProduct>) {
        val arr = JSONArray()
        for (p in products) {
            val o = JSONObject()
            o.put("productId", p.productId)
            o.put("title", p.title)
            o.put("description", p.description)
            o.put("formattedPrice", p.formattedPrice)
            o.put("priceAmountMicros", p.priceAmountMicros)
            o.put("priceCurrencyCode", p.priceCurrencyCode)
            o.put("offerToken", p.offerToken)
            arr.put(o)
        }
        store.putEncryptedString(keyProducts, arr.toString())
    }

    fun getProductSnapshot(): List<IapProduct> {
        val raw = store.getDecryptedString(keyProducts) ?: return emptyList()
        return runCatching {
            val arr = JSONArray(raw)
            (0 until arr.length()).map { i ->
                val o = arr.getJSONObject(i)
                IapProduct(
                    productId = o.optString("productId"),
                    title = o.optString("title"),
                    description = o.optString("description"),
                    formattedPrice = o.optString("formattedPrice"),
                    priceAmountMicros = o.optLong("priceAmountMicros"),
                    priceCurrencyCode = o.optString("priceCurrencyCode"),
                    offerToken = o.optString("offerToken").takeIf { it.isNotBlank() }
                )
            }
        }.getOrElse { emptyList() }
    }

    fun saveOwnedPurchases(purchases: List<Purchase>) {
        val arr = JSONArray()
        for (p in purchases) {
            val o = JSONObject()
            o.put("purchaseToken", p.purchaseToken)
            o.put("products", JSONArray(p.products))
            o.put("purchaseTime", p.purchaseTime)
            o.put("acknowledged", p.isAcknowledged)
            o.put("state", p.purchaseState)
            arr.put(o)
        }
        store.putEncryptedString(keyOwned, arr.toString())
    }
}

private fun WalletSensitiveData.toJson(): JSONObject {
    val o = JSONObject()
    if (!panLast4.isNullOrBlank()) o.put("panLast4", panLast4)
    if (!tokenizedInstrumentId.isNullOrBlank()) o.put("tokenizedInstrumentId", tokenizedInstrumentId)
    if (!billingEmail.isNullOrBlank()) o.put("billingEmail", billingEmail)
    return o
}

class SecureStore(context: Context) {
    private val prefs: SharedPreferences =
        context.getSharedPreferences("secure_store_v1", Context.MODE_PRIVATE)

    private val crypto: CryptoEngine = CryptoEngine(context)

    fun putEncryptedString(key: String, value: String) {
        val enc = crypto.encryptToBase64(value.toByteArray(Charsets.UTF_8))
        prefs.edit().putString(key, enc).apply()
    }

    fun getDecryptedString(key: String): String? {
        val enc = prefs.getString(key, null) ?: return null
        val bytes = crypto.decryptFromBase64(enc) ?: return null
        return runCatching { String(bytes, Charsets.UTF_8) }.getOrNull()
    }

    fun encryptJson(json: String): String = crypto.encryptToBase64(json.toByteArray(Charsets.UTF_8))
    fun decryptJson(blob: String): String? = crypto.decryptFromBase64(blob)?.let { String(it, Charsets.UTF_8) }
}

private class CryptoEngine(private val context: Context) {
    private val alias = "payments_aes_gcm_key_v1"
    private val ksType = "AndroidKeyStore"

    private val legacyPrefs: SharedPreferences =
        context.getSharedPreferences("crypto_legacy_v1", Context.MODE_PRIVATE)

    fun encryptToBase64(plain: ByteArray): String {
        val payload = encrypt(plain)
        return Base64.encodeToString(payload, Base64.NO_WRAP)
    }

    fun decryptFromBase64(enc: String): ByteArray? {
        val payload = runCatching { Base64.decode(enc, Base64.NO_WRAP) }.getOrNull() ?: return null
        return decrypt(payload)
    }

    private fun encrypt(plain: ByteArray): ByteArray {
        return try {
            val key = getOrCreateAesKey()
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            cipher.init(Cipher.ENCRYPT_MODE, key)
            val iv = cipher.iv
            val ct = cipher.doFinal(plain)
            packV1(iv, ct)
        } catch (e: Throwable) {
            val key = getOrCreateLegacyKey()
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            cipher.init(Cipher.ENCRYPT_MODE, key)
            val iv = cipher.iv
            val ct = cipher.doFinal(plain)
            packV1(iv, ct)
        }
    }

    private fun decrypt(payload: ByteArray): ByteArray? {
        val (iv, ct) = unpackV1(payload) ?: return null
        return try {
            val key = getOrCreateAesKey()
            val cipher = Cipher.getInstance("AES/GCM/NoPadding")
            cipher.init(Cipher.DECRYPT_MODE, key, GCMParameterSpec(128, iv))
            cipher.doFinal(ct)
        } catch (_: Throwable) {
            val key = runCatching { getOrCreateLegacyKey() }.getOrNull() ?: return null
            runCatching {
                val cipher = Cipher.getInstance("AES/GCM/NoPadding")
                cipher.init(Cipher.DECRYPT_MODE, key, GCMParameterSpec(128, iv))
                cipher.doFinal(ct)
            }.getOrNull()
        }
    }

    private fun packV1(iv: ByteArray, ct: ByteArray): ByteArray {
        val header = byteArrayOf(0x50, 0x4D, 0x54, 0x01) // 'PMT' + version 1
        val ivLen = iv.size
        val ctLen = ct.size
        val out = ByteArray(header.size + 2 + ivLen + 4 + ctLen)
        var idx = 0
        header.copyInto(out, idx); idx += header.size
        out[idx++] = (ivLen and 0xFF).toByte()
        out[idx++] = ((ivLen ushr 8) and 0xFF).toByte()
        iv.copyInto(out, idx); idx += ivLen
        out[idx++] = (ctLen and 0xFF).toByte()
        out[idx++] = ((ctLen ushr 8) and 0xFF).toByte()
        out[idx++] = ((ctLen ushr 16) and 0xFF).toByte()
        out[idx++] = ((ctLen ushr 24) and 0xFF).toByte()
        ct.copyInto(out, idx)
        return out
    }

    private fun unpackV1(payload: ByteArray): Pair<ByteArray, ByteArray>? {
        if (payload.size < 4 + 2 + 12 + 4) return null
        if (payload[0] != 0x50.toByte() || payload[1] != 0x4D.toByte() || payload[2] != 0x54.toByte()) return null
        if (payload[3] != 0x01.toByte()) return null
        var idx = 4
        val ivLen = (payload[idx++].toInt() and 0xFF) or ((payload[idx++].toInt() and 0xFF) shl 8)
        if (ivLen <= 0 || payload.size < 4 + 2 + ivLen + 4) return null
        val iv = payload.copyOfRange(idx, idx + ivLen); idx += ivLen
        val ctLen = (payload[idx++].toInt() and 0xFF) or
            ((payload[idx++].toInt() and 0xFF) shl 8) or
            ((payload[idx++].toInt() and 0xFF) shl 16) or
            ((payload[idx++].toInt() and 0xFF) shl 24)
        if (ctLen <= 0 || payload.size < idx + ctLen) return null
        val ct = payload.copyOfRange(idx, idx + ctLen)
        return iv to ct
    }

    private fun getOrCreateAesKey(): SecretKey {
        val ks = KeyStore.getInstance(ksType).apply { load(null) }
        val existing = ks.getEntry(alias, null) as? KeyStore.SecretKeyEntry
        if (existing != null) return existing.secretKey

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            val keyGen = KeyGenerator.getInstance("AES", ksType)
            val spec = android.security.keystore.KeyGenParameterSpec.Builder(
                alias,
                android.security.keystore.KeyProperties.PURPOSE_ENCRYPT or android.security.keystore.KeyProperties.PURPOSE_DECRYPT
            )
                .setBlockModes(android.security.keystore.KeyProperties.BLOCK_MODE_GCM)
                .setEncryptionPaddings(android.security.keystore.KeyProperties.ENCRYPTION_PADDING_NONE)
                .setKeySize(256)
                .setRandomizedEncryptionRequired(true)
                .build()
            keyGen.init(spec)
            return keyGen.generateKey()
        } else {
            throw GeneralSecurityException("AndroidKeyStore AES requires API 23+")
        }
    }

    private fun getOrCreateLegacyKey(): SecretKey {
        val keyName = "legacy_aes_key_b64"
        val existingB64 = legacyPrefs.getString(keyName, null)
        if (!existingB64.isNullOrBlank()) {
            val raw = Base64.decode(existingB64, Base64.NO_WRAP)
            return SecretKeySpec(raw, "AES")
        }
        val raw = ByteArray(32)
        SecureRandomCompat.nextBytes(raw)
        legacyPrefs.edit().putString(keyName, Base64.encodeToString(raw, Base64.NO_WRAP)).apply()
        return SecretKeySpec(raw, "AES")
    }
}

private object SecureRandomCompat {
    private val sr by lazy {
        try {
            java.security.SecureRandom()
        } catch (_: Throwable) {
            java.util.Random()
        }
    }

    fun nextBytes(out: ByteArray) {
        when (sr) {
            is java.security.SecureRandom -> (sr as java.security.SecureRandom).nextBytes(out)
            else -> {
                val r = sr as java.util.Random
                for (i in out.indices) out[i] = r.nextInt(256).toByte()
            }
        }
    }
}

object PaymentIdempotency {
    fun deriveKey(userId: String, nonce: String, secret: String): String {
        val mac = Mac.getInstance("HmacSHA256")
        mac.init(SecretKeySpec(secret.toByteArray(Charsets.UTF_8), "HmacSHA256"))
        val out = mac.doFinal("$userId:$nonce".toByteArray(Charsets.UTF_8))
        return Base64.encodeToString(out, Base64.NO_WRAP)
    }
}